// Extract message data + generate session ID
const msg = $input.first().json;
const text = msg.message?.text || '';
const chatId = msg.message?.chat?.id;
const userId = msg.message?.from?.id;
const username = msg.message?.from?.username || 'annar';
const timestamp = new Date().toISOString();
const sessionId = `session_${userId}_${Date.now()}`;

// Simple command routing
let intent = 'general';
if (text.startsWith('/status')) intent = 'status';
else if (text.startsWith('/brief')) intent = 'brief';
else if (text.startsWith('/reset')) intent = 'reset';
else if (text.startsWith('/help')) intent = 'help';

return [{
  json: {
    text,
    chatId,
    userId,
    username,
    timestamp,
    sessionId,
    intent,
    wordCount: text.split(' ').length
  }
}];

// Build system prompt with retrieved context
const userMessage = $('Parse Message').item.json.text;
const contextChunks = $input.first().json;

// Format retrieved context
let contextBlock = '';
if (Array.isArray(contextChunks) && contextChunks.length > 0) {
  contextBlock = contextChunks
    .map(c => `[${c.source || 'context'}]\n${c.content}`)
    .join('\n\n');
} else {
  // Fallback: hardcoded core identity if Supabase returns nothing
  contextBlock = `Du er AIOS — Annars private AI Operating System.
Annar er 21 år, fra Lillehammer. Bygger AIOS og Recruiter Growth OS parallelt med 9-5 jobb og studier.
Kjerneprinsipp: Direkte. Kort. Ærlig. Utfordre når nødvendig. Aldri smigre.`;
}

const systemPrompt = `Du er AIOS — Annars private AI Operating System og nærmeste strategiske partner.

Identitet og mandat:
- Du kjenner Annar bedre enn noen ansatt
- Du er ikke en assistent. Du er en partner som utfordrer, prioriterer og bygger
- Kommuniser alltid på det språket Annar bruker i meldingen
- Vær direkte. Kom til poenget. Ingen innpakning
- Kort som standard. Langt kun når kompleksiteten krever det
- Utfordre hvis Annar er på feil vei — det er jobben din
- Aldri presenter unødvendige valg. Gi én klar anbefaling
- Du er aldri en terapeut. Fokuset er alltid forretning og bygging

Hentet kontekst (RAG):
${contextBlock}

Dato/tid: ${new Date().toISOString()}`;

return [{
  json: {
    systemPrompt,
    userMessage,
    contextFound: Array.isArray(contextChunks) && contextChunks.length > 0
  }
}];

const response = $input.first().json;
const aiText = response.content?.[0]?.text || 'Ingen svar fra Claude.';
const inputTokens = response.usage?.input_tokens || 0;
const outputTokens = response.usage?.output_tokens || 0;

// Rough cost estimate (claude-sonnet-4 pricing)
const costUSD = (inputTokens * 0.000003) + (outputTokens * 0.000015);

return [{
  json: {
    aiText,
    inputTokens,
    outputTokens,
    costUSD: costUSD.toFixed(6),
    model: response.model
  }
}];
